function get_response_time(url) {
  if (url === 'learnwithhasan.com') return 0.5;
  if (url === 'google.com') return 0.3;
  if (url === 'openai.com') return 0.4;
  return 'Unknown URL';
}

function get_site_health(url) {
  var rt = get_response_time(url);
  if (rt === 'Unknown URL') return 'Cannot evaluate health for ' + url + ' - domain not recognized.';
  if (rt < 0.4) return '✅ ' + url + ' is healthy (response time: ' + rt + 's)';
  else return '⚠️ ' + url + ' is slow (response time: ' + rt + 's)';
}

function fetch_json(params) {
  var endpoint = params.endpoint;
  var base_key = params.base_key;
  var url = endpoint;
  var bases = {
    'json_placeholder': 'https://jsonplaceholder.typicode.com',
    'httpbin': 'https://httpbin.org',
    'time_api': 'https://worldtimeapi.org/api'
  };
  if (base_key && bases[base_key]) {
    url = bases[base_key] + endpoint;
  }
  try {
    var resp = UrlFetchApp.fetch(url);
    return JSON.parse(resp.getContentText());
  } catch(e) {
    return { error: e.toString() };
  }
}

function fetch_and_process_user(params) {
  var user_id = params.user_id;
  var data = fetch_json({ endpoint: '/users/' + user_id, base_key: 'json_placeholder' });
  if (data.error) return data;
  return 'User ' + data.id + ': ' + data.name + ' (Email: ' + data.email + ')';
}
